class RangeModule {
    List<int[]> ranges = new ArrayList<>();

    public RangeModule() {

    }

    public void addRange(int left, int right) {
        for (int[] range : ranges) {
            if (range[1] >= left) {
                range[1] = Math.max(range[1], right);
                return;
            }
        }
        ranges.add(new int[]{left, right});
    }

    public boolean queryRange(int left, int right) {
        for (int[] range : ranges) {
            if (range[0] <= right && left <= range[1]) {
                return true;
            }
        }
        return false;
    }

    public void removeRange(int left, int right) {
        List<int[]> newRanges = new ArrayList<>();
        for (int[] range : ranges) {
            if (range[1] <= left || range[0] >= right) {
                newRanges.add(range);
            } else if (range[0] < left) {
                newRanges.add(new int[]{range[0], left});
            } else if (range[1] > right) {
                newRanges.add(new int[]{right, range[1]});
            }
        }
        ranges = newRanges;
    }
}
